class Solution {
    public String minimizeStringValue(String s) {
        char[] chars = s.toCharArray();
        Arrays.sort(chars);
        for (int i = 0; i < chars.length; i++) {
            if (chars[i] == '?') {
                chars[i] = 'a';
            }
        }
        for (int i = 1; i < chars.length; i++) {
            if (chars[i] == chars[i - 1]) {
                chars[i] = (char) (chars[i] + 1);
            }
        }
        return new String(chars);
    }
}
